export function formatAmount(amountInCents: number, currency: string): string {
  const amount = amountInCents / 100;

  let formattedAmount: string;

  if (currency === 'EUR') {
    formattedAmount = new Intl.NumberFormat('de-DE', {
      style: 'currency',
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
  } else if (currency === 'CHF') {
    formattedAmount = new Intl.NumberFormat('de-CH', {
      style: 'currency',
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
    formattedAmount = formattedAmount.replace('CHF', 'Fr.');
  } else if (currency === 'USD') {
    formattedAmount = new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency,
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
  } else {
    throw new Error(`Unsupported currency: ${currency}`);
  }

  return formattedAmount;
}
```
