// models/postModel.ts
import { Schema, model, Document } from 'mongoose';

interface Post extends Document {
  content: string;
  image: string;
  createdAt: Date;
  name: string;
  likes: number;
}

const postSchema = new Schema<Post>({
  content: {
    type: String,
