#include <thread>

void worker(int id) {
    std::cout << "Worker " << id << " started." << std::endl;
    // Perform some work
    std::cout << "Worker " << id << " finished." << std::endl;
}

int main() {
    const int num_workers = 4;
    std::thread workers[num_workers];
    for (int i = 0; i < num_workers; i++) {
        workers[i] = std::thread(worker, i);
    }
